import type { AuditEntry } from '../types.js';

export function archiveAudit(memoryId: string): AuditEntry {
  return {
    id: `archive-${memoryId}`,
    timestamp: new Date().toISOString(),
    operation: 'archive',
    functionId: 'mem::archive',
    targetIds: [memoryId],
    details: { archived: true },
  };
}
